INSERT INTO "condition_periods" ("cat_id", "label", "start_date", "end_date", "health_summary", "treatment_summary") VALUES (1, '2026-02-01 00:00:00', '2026-01-20', NULL, 'Eye status is stable. More morning liquid discharge. No squinting. | No mouth ulcers; regular energy-appetite levels. | Does reduction / elimination of inflamation signs on eye and elimination of lip ulcer. Often with execessive liquid discharge in the morning, but after cleaning, good condition. No squinting.', NULL);
